import { MakeLogicType, afterMount, kea, path, selectors } from 'kea'
import { loaders } from 'kea-loaders'

import api from 'lib/api'
import { toParams } from 'lib/utils/url'

import type { SessionRecordingPlaylistType } from '~/types'


const toOptions = (
    playlists: SessionRecordingPlaylistType[],
    unnamedLabel: string
): { value: string; label: string }[] =>
    playlists.map((playlist) => ({
        value: playlist.short_id,
        label: playlist.name || playlist.derived_name || unnamedLabel,
    }))

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface sessionReplayWidgetSavedFiltersLogicValues {
    collectionLabelById: Record<string, string>;
    collectionOptions: {
        label: string;
        value: string;
    }[];
    collections: SessionRecordingPlaylistType[];
    collectionsLoading: boolean;
    savedFilterLabelById: Record<string, string>;
    savedFilterOptions: {
        label: string;
        value: string;
    }[];
    savedFilters: SessionRecordingPlaylistType[];
    savedFiltersLoading: boolean;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface sessionReplayWidgetSavedFiltersLogicActions {
    loadCollections: () => any;
    loadCollectionsFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadCollectionsSuccess: (collections: SessionRecordingPlaylistType[], payload?: any) => {
        collections: SessionRecordingPlaylistType[];
        payload?: any;
    };
    loadSavedFilters: () => any;
    loadSavedFiltersFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadSavedFiltersSuccess: (savedFilters: SessionRecordingPlaylistType[], payload?: any) => {
        savedFilters: SessionRecordingPlaylistType[];
        payload?: any;
    };
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface sessionReplayWidgetSavedFiltersLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        savedFilterOptions: (savedFilters: SessionRecordingPlaylistType[]) => {
            label: string;
            value: string;
        }[];
        collectionOptions: (collections: SessionRecordingPlaylistType[]) => {
            label: string;
            value: string;
        }[];
        savedFilterLabelById: (savedFilterOptions: {
            label: string;
            value: string;
        }[]) => Record<string, string>;
        collectionLabelById: (collectionOptions: {
            label: string;
            value: string;
        }[]) => Record<string, string>;
    };
}

export type sessionReplayWidgetSavedFiltersLogicType = MakeLogicType<sessionReplayWidgetSavedFiltersLogicValues, sessionReplayWidgetSavedFiltersLogicActions, Record<string, any>, sessionReplayWidgetSavedFiltersLogicMeta>;

// Saved session replay filters and collections are both SessionRecordingPlaylist rows, distinguished by
// type ("filters" vs "collection"). The widget can source recordings from either, so we load both here.
export const sessionReplayWidgetSavedFiltersLogic = kea<sessionReplayWidgetSavedFiltersLogicType>([
    path(['products', 'dashboards', 'widgets', 'session_replay', 'sessionReplayWidgetSavedFiltersLogic']),
    loaders({
        savedFilters: {
            __default: [] as SessionRecordingPlaylistType[],
            loadSavedFilters: async () => {
                const response = await api.recordings.listPlaylists(
                    toParams({ limit: 100, order: '-last_modified_at', type: 'filters' })
                )
                return response.results
            },
        },
        collections: {
            __default: [] as SessionRecordingPlaylistType[],
            loadCollections: async () => {
                const response = await api.recordings.listPlaylists(
                    toParams({ limit: 100, order: '-last_modified_at', type: 'collection' })
                )
                return response.results
            },
        },
    }),
    selectors({
        savedFilterOptions: [
            (s) => [s.savedFilters],
            (savedFilters: SessionRecordingPlaylistType[]): { value: string; label: string }[] => toOptions(savedFilters, 'Unnamed filter'),
        ],
        collectionOptions: [
            (s) => [s.collections],
            (collections: SessionRecordingPlaylistType[]): { value: string; label: string }[] => toOptions(collections, 'Unnamed collection'),
        ],
        // Single source for resolving a saved-filter short_id to its display label, shared by the
        // tile filter bar and the card header top heading.
        savedFilterLabelById: [
            (s) => [s.savedFilterOptions],
            (savedFilterOptions: {
    label: string;
    value: string;
}[]): Record<string, string> =>
                Object.fromEntries(savedFilterOptions.map((option) => [option.value, option.label])),
        ],
        collectionLabelById: [
            (s) => [s.collectionOptions],
            (collectionOptions: {
    label: string;
    value: string;
}[]): Record<string, string> =>
                Object.fromEntries(collectionOptions.map((option) => [option.value, option.label])),
        ],
    }),
    afterMount(({ actions, cache }) => {
        actions.loadSavedFilters()
        actions.loadCollections()
        // The "Create a collection / saved filter" shortcuts open session replay in a new tab. Reload both
        // lists when the user returns so a just-created collection/filter is selectable without a page refresh.
        cache.disposables.add(
            () => {
                const handler = (): void => {
                    if (document.visibilityState === 'visible') {
                        actions.loadSavedFilters()
                        actions.loadCollections()
                    }
                }
                document.addEventListener('visibilitychange', handler)
                return () => document.removeEventListener('visibilitychange', handler)
            },
            'reloadOnTabFocus',
            { pauseOnPageHidden: false }
        )
    }),
])
